import React, { useMemo, useEffect, useRef, useState } from "react";
import Grid from "./components/Grid/Grid";
import { getImage } from "./utils/getImage";
import { Helmet } from 'react-helmet-async';
import { HelmetProvider } from 'react-helmet-async';
import data from "./data/portfolio.json";
const rawItems = data.items;
const { temas, tags, usos } = data.dicts;
const items = rawItems.map((item) => {
  const temasLabels = item.meta.temas.map((i) => temas[i]);
  const tagsLabels = item.meta.tags.map((i) => tags[i]);
  const usosLabels = item.meta.usos.map((i) => usos[i]);

  const allFilters = [...temasLabels, ...tagsLabels, ...usosLabels];
  const allFiltersLower = allFilters.map(f => f.toLowerCase());

  // Corregir categoría: mapear "otros" según el prefijo del ID
  let categoria = item.categoria;
  if (categoria === "otros") {
    if (item.id.startsWith("ilu-")) {
      categoria = "ilustracion";
    } else if (item.id.startsWith("dis-")) {
      categoria = "diseno";
    }
  }

  return {
    ...item,
    categoria, // ← Sobreescribimos con la categoría corregida
    temasLabels,
    tagsLabels,
    usosLabels,
    allFilters,
    allFiltersLower,
  };
});

/* =========================
   1) UTILIDADES
========================= */
const gridCardBase = {
  all: "unset",
  display: "block",
  cursor: "pointer",
  width: "100%",
  borderRadius: "12px",
  overflow: "hidden",
  background: "#fff",
  transition: "all 0.25s ease",
};
const useInView = (ref) => {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    if (!("IntersectionObserver" in window)) {
      setVisible(true);
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisible(true);
            observer.unobserve(el);
          }
        });
      },
      {
        rootMargin: "150px 0px",
        threshold: 0.01,
      }
    );

    observer.observe(el);

    return () => {
      observer.unobserve(el); // ✅ también aquí
      observer.disconnect();
    };
  }, [ref]);

  return visible;
};
const GridItem = React.memo(function GridItem({
  item,
  selectedId,
  hoveredId,
  setHovered,
  changeSelected,
  isSingle,
}) {
  return (
    <button
      type="button"
      onClick={() => changeSelected(item)}
      aria-label={`Ver ${item.titulo}`}
      onMouseEnter={() => setHovered(item.id)}
      onMouseLeave={() => setHovered(null)}
      style={{
        ...gridCardBase,
        border: selectedId === item.id ? "2px solid #666" : "1px solid #e5e5e5",
        transform: hoveredId === item.id ? "translateY(-6px)" : "translateY(0)",
        boxShadow:
          hoveredId === item.id
            ? "0 8px 18px rgba(0,0,0,0.12)"
            : "0 1px 4px rgba(0,0,0,0.04)",
        maxWidth: isSingle ? "clamp(300px, 50vw, 500px)" : "100%",
      }}
    >
      <div
  style={{
    width: "100%",
    height: "200px",
    overflow: "hidden",
    borderTopLeftRadius: "12px",
    borderTopRightRadius: "12px",
    background: "#fff", // ← Asegurar fondo blanco
    position: "relative",
  }}
>
  <LazyImage
    src={getImage(item, "thumb")}
    alt={item.titulo}
    style={{
      width: "100%",
      height: "100%",
      objectFit: "contain", // ← CAMBIADO de "cover" a "contain"
      objectPosition: "center", // ← CAMBIADO de "top" a "center"
      position: "absolute",
      top: 0,
      left: 0,
    }}
  />
</div>
      <div style={{ padding: "10px" }}>
