          © AMP 2026
        </div>
        <img
          src="/logo.png"
          alt="Marist-Art"
          style={{
            height: "40px",
            objectFit: "contain",
            cursor: "pointer",
            opacity: 0.9,
            transition: "opacity 0.2s ease",
          }}
          onMouseEnter={(e) => (e.currentTarget.style.opacity = 1)}
          onMouseLeave={(e) => (e.currentTarget.style.opacity = 0.9)}
          onClick={() => {
            setQuery("");
            setSelectedCategory("todas");
